  Created = 'Created',
  /** The token has been discovered */
  Deployed = 'Deployed',
  /** The token has been migrated */
  Migrated = 'Migrated',
  /** The token has been discovered (not finalized) */
  UnconfirmedDeployed = 'UnconfirmedDeployed',
